fn test_hub_dampening() {
        let n1 = NodeIndex::new(0);
        let n2 = NodeIndex::new(1);

        let mut scores: HashMap<NodeIndex, f32> = HashMap::new();
        scores.insert(n1, 1.0);
        scores.insert(n2, 1.0);

