        assert!(results.is_empty());
    }

    #[test]
    fn test_rrf_merge_single_source() {
        let vector = vec![
            ("a".to_string(), 0.9),
            ("b".to_string(), 0.8),
            ("c".to_string(), 0.7),
        ];
