                    "lexical_score": lexical_score,
                    "exact_score": exact_score,
                    "vector_score": scores.vector_score,
                    "bm25_score": scores.bm25_score,
                    "ppr_score": scores.ppr_score,
                }),
            )
        })
    })
    .collect();
