    query.contains('_')
        || query.contains("::")
        || query.contains('/')
        || query.contains('.')
        || query
            .chars()
            .zip(query.chars().skip(1))
            .any(|(a, b)| a.is_ascii_lowercase() && b.is_ascii_uppercase())
        || terms.iter().any(|t| {
            matches!(
                t.as_str(),
                "fn" | "impl" | "struct" | "trait" | "class" | "method"
            )
        })
}

